-- Egyptian food macro seed data from user-provided approximate macro table.
-- These values are practical fitness estimates, not medical-grade nutrition data.
on conflict on constraint food_items_unique_source do update set
  calories = excluded.calories,
  protein_g = excluded.protein_g,
  carbs_g = excluded.carbs_g,
  fat_g = excluded.fat_g,
  category = excluded.category,
  cuisine = excluded.cuisine,
  aliases = excluded.aliases,
  updated_at = now();
